Highcharter OHLC chart

# Get Amazon stock data from yahoo finance with quantmod

ticker &lt;- "AMZN"

stocks &lt;- getSymbols(
    ticker,
    from = "1990-01-01",
    auto.assign = FALSE
)

# Stock OHLC interactive chart with highchart

highchart(type = "stock") |&gt; 
    hc_chart(inverted = FALSE) |&gt; 
    hc_title(text = ticker) |&gt; 
    hc_add_series(
        stocks,
        yAxis = 0,
        showInLegend = FALSE,
        color = "black"
    ) |&gt; 
    hc_add_yAxis(
        nid = 1L,
        title = list(text = "Prices"),
        relative = 2
    ) |&gt; 
    hc_add_series(
        Vo(stocks), 
        yAxis = 1,
        type = "column",
        showInLegend = FALSE
    ) |&gt; 
    hc_add_yAxis(
        nid = 2L,
        title = list(text = "Volume"),
        relative = 1
    )

